import{_ as t,o as a,c as r,a2 as i}from"./chunks/framework.Crpw6aS5.js";const s="/assets/01-mq135-board-photo.BbDB7X0A.png",o="/assets/02-mq135-board-components-led.CPz2bWdX.png",n="/assets/03-datasheet-internal-structure.C2VNXwxH.png",l="/assets/04-datasheet-sensitivity-curve.C7kclms6.png",d="/assets/05-co2-earth-reference-chart.BTQPXpDc.png",c="/assets/06-sensor-diagram-divider.p41F24Na.jpg",p="/assets/07-circuit-diagram.DghJRs2L.jpg",h="/assets/08-lolin-mini-pinout-front.Bdp0c0DR.png",g="/assets/09-lolin-mini-pinout-back.BkpzNbUY.png",m="/assets/10-oled-wiring-photo.uItXQbmp.png",u="/assets/11-epa-airnow-aqi13.03K7a2KI.jpg",b="/assets/12-oled-calibration-display.BOGeahmA.jpg",f="/assets/13-oled-aqi-display.Dq_LtSnR.jpg",k="/assets/14-ha-history-coffee-humidex.JaLaqOie.jpg",y="/assets/15-ha-history-humidex-coffee.CBgbXrmX.jpg",A="/assets/16-epa-airnow-aqi60.beWR7-43.jpg",E="/assets/17-ha-lovelace-gauge-card.eXXGQ3sc.png",q="/assets/18-ha-history-graph-params.JM7N6eoO.png",R=JSON.parse('{"title":"MQ135 Air Quality Sensor (Bobbo117)","description":"Notes on MQ135 Air Quality Sensor (Bobbo117).","frontmatter":{"title":"MQ135 Air Quality Sensor (Bobbo117)","description":"Notes on MQ135 Air Quality Sensor (Bobbo117)."},"headers":[],"relativePath":"microcontrollers-and-socs/github-bobbo117-mq135-air-quality-sensor.md","filePath":"microcontrollers-and-socs/github-bobbo117-mq135-air-quality-sensor.md"}'),v={name:"microcontrollers-and-socs/github-bobbo117-mq135-air-quality-sensor.md"};function w(_,e,D,M,Q,x){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="mq135-air-quality-sensor-bobbo117" tabindex="-1">MQ135 Air Quality Sensor (Bobbo117) <a class="header-anchor" href="#mq135-air-quality-sensor-bobbo117" aria-label="Permalink to &quot;MQ135 Air Quality Sensor (Bobbo117)&quot;">​</a></h1><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li>Type: webpage</li><li>Origin: <a href="https://github.com/Bobbo117/MQ135-Air-Quality-Sensor" target="_blank" rel="noreferrer">https://github.com/Bobbo117/MQ135-Air-Quality-Sensor</a></li><li>Imported: 2026-05-21</li><li>Figures: eighteen images mirrored under <code>assets/github-bobbo117-mq135-air-quality-sensor/</code> from the repository README (<code>user-images.githubusercontent.com</code> and <code>raw.githubusercontent.com</code>).</li></ul><h2 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h2><h3 id="project-overview" tabindex="-1">Project overview <a class="header-anchor" href="#project-overview" aria-label="Permalink to &quot;Project overview&quot;">​</a></h3><p>Project connects an MQ135 sensor board to an Arduino-class controller for <strong>outdoor calibration</strong> of that specific board, then <strong>indoor monitoring</strong> biased toward CO₂ (with caveats noted by the author). Reporting options described:</p><ol><li>Computer over USB via Arduino IDE</li><li>OLED display</li><li>ThingSpeak</li><li>Home Assistant via MQTT (<code>aqi/mq135</code>)</li></ol><p>Upstream repository: <a href="https://github.com/Bobbo117/MQ135-Air-Quality-Sensor" target="_blank" rel="noreferrer">https://github.com/Bobbo117/MQ135-Air-Quality-Sensor</a></p><h3 id="mq135-board-carrier" tabindex="-1">MQ135 board (carrier) <a class="header-anchor" href="#mq135-board-carrier" aria-label="Permalink to &quot;MQ135 board (carrier)&quot;">​</a></h3><p>The breakout has four pins: Vcc (5 V), GND, A0 (analog voltage), and D0 (digital). It includes the MQ135, power LED, alarm LED, potentiometer for alarm threshold on D0, load resistor RL, and circuitry for digital output.</p><p><img src="'+s+'" alt="MQ135 breakout — pinout and face"></p><p><img src="'+o+'" alt="Board components — alarm LED / potentiometer"></p><p>Digital output goes active (low in the README’s wording—verify against your wiring) together with alarm LED once A0-derived voltage crosses the adjusted threshold. The MQ135 capsule has an <strong>explosion shield</strong> around the sensing element.</p><h3 id="mq135-sensing-element" tabindex="-1">MQ135 sensing element <a class="header-anchor" href="#mq135-sensing-element" aria-label="Permalink to &quot;MQ135 sensing element&quot;">​</a></h3><p><a href="https://www.olimex.com/Products/Components/Sensors/Gas/SNS-MQ135/resources/SNS-MQ135.pdf" target="_blank" rel="noreferrer">Olimex datasheet (PDF)</a>: gas-sensitive layer changes resistance. Internal structure excerpt (diagram from datasheet as shown in README):</p><p><img src="'+n+'" alt="Datasheet excerpt — sensor internal structure"></p><p>Pins: paired <strong>H</strong> pads for heater (~35 Ω cold per author); <strong>A/A</strong> tied to <strong>B/B</strong> forming Rs. On the author’s carrier, A side to Vcc, B side to A0 pad and RL to GND (midpoint divider at A0). Sensitivity characteristics excerpt:</p><p><img src="'+l+'" alt="Datasheet excerpt — sensitivity / Rs vs gas"></p><p>Outdoor CO₂ baseline context from <a href="https://www.co2.earth/" target="_blank" rel="noreferrer">CO2.Earth</a> (400+ ppm ambient; interiors often &gt;1000 ppm):</p><p><img src="'+d+'" alt="CO2 Earth style reference graphic from README"></p><p>Takeaway stated in README: indoors, other MQ135-cross-sensitive gases often low; probe may still approximate CO₂ alongside “general VOC” interpretations—<strong>confirmed cross-sensitivity caveats appear later.</strong></p><h3 id="divider-model-rs-vs-rl-vs-a0" tabindex="-1">Divider model (Rs vs RL vs A0) <a class="header-anchor" href="#divider-model-rs-vs-rl-vs-a0" aria-label="Permalink to &quot;Divider model (Rs vs RL vs A0)&quot;">​</a></h3><p>Increasing target gas concentration lowers Rs; Rs and RL form a divider so <strong>A0 voltage rises with ppm</strong> when wired as documented.</p><p><img src="'+c+'" alt="Voltage-divider schematic as in README"></p><p><strong>Board-specific numbers (author):</strong> unpowered, measure <strong>sensor resistance between VCC and A0</strong> (~1750 Ω); measure <strong>RL from A0 to GND</strong> (~1720 Ω). Enter RL in kilohms in <code>#define RLOAD</code> inside <code>MQ135_Air_Quality.ino</code>.</p><h3 id="hardware-connections" tabindex="-1">Hardware connections <a class="header-anchor" href="#hardware-connections" aria-label="Permalink to &quot;Hardware connections&quot;">​</a></h3><p><img src="'+p+'" alt="Wiring / circuit sketch from README"></p><p>Use ESP8266, ESP32, or 5 V–tolerant Arduino per flags in sketch—author used <strong>Lolin D1 Mini (ESP8266)</strong>.</p><p><img src="'+h+'" alt="ESP8266 D1 Mini pinout (front)"></p><p><img src="'+g+'" alt="ESP8266 D1 Mini pinout (back)"></p><p><strong>MQ135:</strong></p><ol><li>VCC → ESP8266 5 V</li><li>GND → ESP8266 GND</li><li>A0 → ESP8266 ADC <strong>through resistor divider</strong></li><li>D0 unused in example</li></ol><p>* <strong>Divider:</strong> roughly <strong>170 kΩ / 330 kΩ</strong> pulls the MQ135 analog maximum down for <strong>3.3 V</strong> ADC-safe input—omit divider on 5 V–tolerant boards.</p><p><img src="'+m+'" alt="OLED module wiring snapshot"></p><p><strong>OLED (I²C assumed per wiring sketch):</strong></p><ol><li>VCC → 3.3 V</li><li>GND → GND</li><li>SDA → SDA</li><li>SCL → SCL</li></ol><h3 id="calibration-approach" tabindex="-1">Calibration approach <a class="header-anchor" href="#calibration-approach" aria-label="Permalink to &quot;Calibration approach&quot;">​</a></h3><p>Formal datasheet calibration expects controlled chamber plus specific RL (~20 kΩ). Author substitutes <strong>fresh outdoor air calibration</strong> matching indoor T/RH reasonably well; cross-check EPA <a href="https://www.airnow.gov/airnow-mobile-app/" target="_blank" rel="noreferrer">AirNow</a> when possible.</p><p><img src="'+u+'" alt="AirNow app screenshot excerpt (EPA AQI 13)"></p><h3 id="software-arduino-mq135-library" tabindex="-1">Software (Arduino MQ135 library) <a class="header-anchor" href="#software-arduino-mq135-library" aria-label="Permalink to &quot;Software (Arduino MQ135 library)&quot;">​</a></h3><p>Install <strong>MQ135</strong> via Arduino IDE Library Manager → use <code>MQ135_Air_Quality.ino</code>.</p><p><strong>Calibrate:</strong></p><ol><li>Measure RL <strong>A0–GND</strong> ohms → set <code>#define RLOAD</code> in kΩ.</li><li>Uncomment <code>#define CALIBRATE</code>.</li><li>Flash; power <strong>outdoors hours</strong> until <code>RZERO</code>/<code>R0</code> stabilizes → read from serial/OLED/Home Assistant/etc.</li><li>Freeze value in <code>#define RZERO xx.xx</code>, comment <code>CALIBRATE</code> again, reflash.</li></ol><p><img src="'+b+'" alt="OLED during calibration/R0 smoothing"></p><p><strong>Monitor:</strong></p><p>Disable <code>CALIBRATE</code>, bake in measured <code>RZERO</code>, reflash—the OLED tracks latest ppm plus rolling seven-sample average:</p><p><img src="'+f+'" alt="OLED during normal AQI readout"></p><h3 id="representative-readings-after-outdoor-calibration" tabindex="-1">Representative readings (after outdoor calibration) <a class="header-anchor" href="#representative-readings-after-outdoor-calibration" aria-label="Permalink to &quot;Representative readings (after outdoor calibration)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Condition</th><th style="text-align:right;">Rough ppm</th></tr></thead><tbody><tr><td>Outside Maine, 75 °F / 63% RH</td><td style="text-align:right;">415</td></tr><tr><td>Kitchen, windows open</td><td style="text-align:right;">500</td></tr><tr><td>Kitchen, shut</td><td style="text-align:right;">600</td></tr><tr><td>Kitchen, oven on</td><td style="text-align:right;">900</td></tr><tr><td>Basement idle</td><td style="text-align:right;">600</td></tr><tr><td>Basement with humidex</td><td style="text-align:right;">550</td></tr></tbody></table><p>(Author references CO₂.Earth for outdoor baseline and notes Shark air-quality device readings alongside.)</p><h3 id="scenario-traces-home-assistant" tabindex="-1">Scenario traces (Home Assistant) <a class="header-anchor" href="#scenario-traces-home-assistant" aria-label="Permalink to &quot;Scenario traces (Home Assistant)&quot;">​</a></h3><p>Movement / coffee / humidex interplay over one morning—timelines authored in HA:</p><p><img src="'+k+'" alt="HA history — coffee + humidex dip"></p><p><img src="'+y+'" alt="HA history — humidex vs second coffee / dishwasher spike"></p><p>Smoke / PM excursion: MQ135 inflated (~2500) while Shark reported moderate PM fractions; EPA AirNow AQI 60 during wildfires:</p><p><img src="'+A+`" alt="EPA AirNow AQI ~60 excerpt"></p><h3 id="home-assistant-mqtt-sensor" tabindex="-1">Home Assistant MQTT sensor <a class="header-anchor" href="#home-assistant-mqtt-sensor" aria-label="Permalink to &quot;Home Assistant MQTT sensor&quot;">​</a></h3><p>MQTT topic <strong><code>aqi/mq135</code></strong> (unit ppm). YAML fragment for <code>mqtt</code> sensor stanza (adapt to your MQTT integration layout):</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">sensor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">unique_id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">mq135</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;MQ135&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    state_topic</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;aqi/mq135&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    qos</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    unit_of_measurement</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ppm&quot;</span></span></code></pre></div><p>Gauge card screenshot from README:</p><p><img src="`+E+'" alt="Lovelace gauge example"></p><p>History graph screenshot:</p><p><img src="'+q+'" alt="HA history-graph configuration snapshot"></p><h3 id="operating-notes-limitations" tabindex="-1">Operating notes / limitations <a class="header-anchor" href="#operating-notes-limitations" aria-label="Permalink to &quot;Operating notes / limitations&quot;">​</a></h3><ul><li><strong>48-hour</strong> burn-in advised before trusting readings.</li><li>Heater warmup after power cycles—few minutes stabilization.</li><li>D0 alarm threshold trimmed via onboard potentiometer.</li><li>Firmware assumes <strong>10-bit</strong> ADC semantics (counts to 1023 in library math)—match MCU configuration.</li><li><strong>No humidity/temperature compensation</strong> in author’s sketch.</li><li><strong>Observations:</strong> clear outdoor days correlate with CO₂-ish trends vs AirNow; <strong>high PM₂.₅ episodes</strong> overwhelm channel so MQ135-derived “ppm” loses CO₂ interpretability—cross-sensitivity wins.</li></ul><h3 id="conclusions-author-tone" tabindex="-1">Conclusions (author tone) <a class="header-anchor" href="#conclusions-author-tone" aria-label="Permalink to &quot;Conclusions (author tone)&quot;">​</a></h3><p>Trend readouts feel useful despite unknown absolute ppm accuracy—pair with calibrated CO₂ monitor if stakes are medical or regulatory.</p><p>Possible future extensions: quantify error budget; federate MQ-2…MQ-9 class sensors to discriminate gases upstream claims.</p><h3 id="attributions-and-references" tabindex="-1">Attributions and references <a class="header-anchor" href="#attributions-and-references" aria-label="Permalink to &quot;Attributions and references&quot;">​</a></h3><ul><li><a href="http://davidegironi.blogspot.com/2014/01/cheap-co2-meter-using-mq135-sensor-with.html" target="_blank" rel="noreferrer">http://davidegironi.blogspot.com/2014/01/cheap-co2-meter-using-mq135-sensor-with.html</a></li><li><a href="https://hackaday.io/project/3475-sniffing-trinket/log/12363-mq135-arduino-library" target="_blank" rel="noreferrer">https://hackaday.io/project/3475-sniffing-trinket/log/12363-mq135-arduino-library</a></li><li><a href="https://gml.noaa.gov/ccgg/trends/gl_data.html" target="_blank" rel="noreferrer">https://gml.noaa.gov/ccgg/trends/gl_data.html</a></li></ul><h2 id="key-takeaways" tabindex="-1">Key takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key takeaways&quot;">​</a></h2><ul><li>Treat MQ135-derived “ppm” as <strong>semi-quantitative</strong>; calibrate RL and RZERO per board outdoors, then sanity-check versus independent references (AirNow, dedicated CO₂).</li><li>Protect <strong>ESP8266/ESP32</strong> ADC inputs with resistor divider unless analog front end is explicitly 5 V tolerant on that pin.</li><li><strong>Home Assistant telemetry</strong> hinges on MQTT topic <code>aqi/mq135</code>; graphing parallels ThingSpeak workflows.</li><li><strong>High particulate episodes</strong> materially falsify inferred CO₂ from MQ135—the sensor is chemically promiscuous; interpret traces in ambient context.</li></ul>',72)])])}const S=t(v,[["render",w]]);export{R as __pageData,S as default};
